sql:
SELECT COUNT(data_id) 
FROM chip_seq_data 
WHERE cell_type = 'HeLa' AND treatment = 'None' AND replicate = 1 AND quality_score = 0.95;

SELECT gene_id, expression_value 
FROM rna_seq_data 
WHERE expression_value > 0.8;

SELECT MAX(expression_value) AS highest_expression
FROM (
  SELECT expression_value FROM microarray_data
  UNION ALL
  SELECT expression_value FROM rna_seq_data
);

SELECT COUNT(*) 
FROM gene_mark_data 
WHERE data_source = 'ChIP-seq';

SELECT gene_id, value
FROM gene_mark_data
WHERE data_source = 'ChIP-seq';

SELECT data_source, AVG(value) AS average_value
FROM gene_mark_data
GROUP BY data_source;

external_knowledge:
- 'Signal transducer' refers to genes involved in the process of converting external signals into cellular responses;
- 'Gene Ontology (GO) terms' are standardized terms used to describe the functions, processes, and locations of genes;
- 'Epigenetic mark' refers to chemical modifications to DNA or histone proteins that affect gene expression without changing the DNA sequence.

- 'histone modification' refers to chemical modifications to histone proteins, which can affect gene expression;
- 'value greater than 0.5' suggests a significant level of the epigenetic mark, indicating a possible active or repressive state of the gene;
- 'Homo sapiens' refers to the human species.

sql:
SELECT mark_name
FROM epigenetic_marks
WHERE mark_type = 'histone modification' AND biological_process = 'Transcription initiation';

